static inline void afn_sram_save(void) {
    volatile u8* sram = (volatile u8*)0x0E000000;
    sram[0] = 'A'; sram[1] = 'F'; // magic
    int i; for (i = 0; i < 4; i++) sram[2+i] = (afn_flags >> (i*8)) & 0xFF;
    for (i = 0; i < 4; i++) sram[6+i] = (afn_score >> (i*8)) & 0xFF;
}
static inline void afn_sram_load(void) {
    volatile u8* sram = (volatile u8*)0x0E000000;
    if (sram[0] != 'A' || sram[1] != 'F') return;
    afn_flags = sram[2] | (sram[3]<<8) | (sram[4]<<16) | (sram[5]<<24);
    afn_score = sram[6] | (sram[7]<<8) | (sram[8]<<16) | (sram[9]<<24);
}
